import React, { useState } from 'react';
// @ts-ignore
import emailjs from 'emailjs-com';
import './styles/global.css';
import './styles/tokens.css';

const EMAILJS_SERVICE_ID = 'service_ehf05es'; // 
const EMAILJS_TEMPLATE_ID = 'template_t1138kn';
const EMAILJS_USER_ID = 'f7BZO-3hAYB-QusoW'; // <-- Replace with your EmailJS user ID (public key)
const PROVIDER_EMAIL = 'anderson.t.ryan@gmail.com';

const categories = [
  {
    name: 'Tshirt (Men)',
    path: 'tshirt/men',
    images: [
      'M100444086 SH2FDS Custom School DTF on Steel .png',
      'M100435370 SDVECS Vector DTF on Steel .png',
      'M100438285 SDARMS Aristotle DTF on Steel.png',
      'M101005933 SDOLAS Overlay DTF on Steel .png',
      'M100435821 SH2FDS Custom State DTF on Steel.png',
      'M100965141 SHDCDW Dad Club DTF on Forest .png',
      'M100965024 SHDCDS Dad Club DTF on Steel.png',
      'M100965414 SHOUDC OU Go Green DTF on Forest.png',
      'M100482538 SHHODC Hover DTF on Black or Forest .png',
      'M100437896 SHOUDC Over Under DTF on Forest.png',
      'M101010777 SH2FDC Custom Go Green DTF of Forest .png',
      'M100431261 SDRENC Renown Mascot DTF on Forest.png',
      'M100432187 SDFREG Frege DTF on Forest .png',
      'M100430821 SH2FDW Custom S DTFN on Forest.png',
      'M100430257 SH2FDW Custom Spartan DTFN on Forest .png',
    ],
  },
  {
    name: 'Tshirt (Women)',
    path: 'tshirt/women',
    images: [
      'M100966592 SDVGIC Jr Valley Girl DTF on Forest.png',
      'M100438745 SDLOCS Locke DTFN on Steel .png',
      'M100965923 SDVGIS Jr Valley Girl DTF on Steel .png',
      'M100964847 SHMCDS Jr Mom Club DTF on Steel.png',
      'M100964663 SDFAMS Jr Family DTF on Steel .png',
      'M100436060 SH2FDS Custom Spartan DTFN on Steel.png',
      'M100439889 SDABSC Absent DTF on Fores.png',
      'M100963545 SHMCDW Jr Mom Club DTF on Green .png',
      'M100963714 SDFAMW Jr Family DTF on Forest.png',
      'M100438383 SH2FDW Custom DTFN on Forest.png',
    ],
  },
  {
    name: 'Raincoat',
    path: 'raincoat',
    images: [
      'M100490133 SEASLW Aspire Jacket .png',
      'M100490691 SHE2CJ Custom Forest Green Jacket.png',
      'M100490842 SDLCJA Custom Logo Gray Jacket.png',
    ],
  },
  {
    name: 'PJ',
    path: 'pj',
    images: [
      'M100445564 SDBOPF Bondi DTF Flannels .png',
      'M100446076 SHFDDF Force down DTF Flannels .png',
      'M100445359 SHPHFD Custom DTF Flannels.png',
    ],
  },
  {
    name: 'Sweatpant',
    path: 'sweatpant',
    images: [
      'M100447223 SHVSCD Value DTF Gray Pants .png',
      'M100448649 SHFDDS Force Down DTF Gray Pants.png',
      'M100446293 SHPSDS Shake it DTF Gray Pants.png',
    ],
  },
  {
    name: 'Short',
    path: 'short',
    images: [
      'M100453813 SHSHDS Custom DTF Gray Shorts .png',
      'M100453381 SHCCDS Carbon Copy DTF Gray Shorts.png',
    ],
  },
  {
    name: 'Hat',
    path: 'hat',
    images: [
      'M100489153 SHE1CH Custom Hat on White or Grays .png',
      'M100488283 SHE1CH Custom Logo on White or Gray.png',
      'M100485992 SHE2CH Custom Spartan on Green .png',
      'M100487428 SECHHC Chirp Gray Hat.png',
      'M100489250 SHE1CH Custom Hat on Forest .png',
      'M100490059 SHEHFL Front Line Forest Green Hat.png',
    ],
  },
  {
    name: 'Beanie',
    path: 'beanie',
    images: [
      'M100494173 SHE1CB Custom Spartan Gray Beanie .png',
      'M101011832 SHERBE Rugby Forest Beanie.png',
      'M100494213 SHE2CB Custom Green Beanie .png',
      'M100492686 SHETMB Talisman Green Beanie.png',
    ],
  },
  {
    name: 'Sock',
    path: 'sock',
    images: [
      'M100415850 SS8052 Custom Logo Socks .png',
      'M100497935 SS8052 Custom Michigan State Socks.png',
    ],
  },
  {
    name: 'Bottle',
    path: 'bottle',
    images: [
      'M100454089 SHWBOT Custom Water Bottle .png',
    ],
  },
  {
    name: 'Card',
    path: 'card',
    images: [
      'M100516676 SHWGCH PFD Header Card.png',
      'M100516533 SHWGCS Spinner Header Card.png',
    ],
  },
];

function App() {
  const [formData, setFormData] = useState({
    storeNumber: '',
    storeManager: '',
    date: new Date().toISOString().split('T')[0],
    quantities: {} as Record<string, string>
  });
  const [error, setError] = useState<string | null>(null);
  const [page, setPage] = useState<'form' | 'summary' | 'receipt'>('form');
  const [sending, setSending] = useState(false);

  // Helper to get all image paths for required check
  const allImagePaths = categories.flatMap(cat => cat.images.map(img => `${cat.path}/${img}`));

  const handleQuantityChange = (imagePath: string, value: string) => {
    setFormData(prev => ({
      ...prev,
      quantities: {
        ...prev.quantities,
        [imagePath]: value
      }
    }));
  };

  const handleFormSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    // Check all required fields
    if (!formData.storeNumber.trim() || !formData.storeManager.trim() || !formData.date.trim()) {
      setError('Please fill out all store information fields.');
      return;
    }
    for (const path of allImagePaths) {
      if (!formData.quantities[path] || formData.quantities[path].trim() === '') {
        setError('Please enter a quantity for every product.');
        return;
      }
    }
    setError(null);
    setPage('summary');
  };

  const handleBack = () => {
    setPage('form');
  };

  const handleConfirm = async () => {
    if (!window.confirm('Are you sure you want to submit this order?')) return;
    setSending(true);

    try {
      // Create categories array with items for the new template format
      const emailCategories = categories.map((cat: any) => ({
        category: cat.name,
        items: cat.images.map((img: string) => {
          const imagePath = `${cat.path}/${img}`;
          const sku = img.split(' ')[0]; // Extract SKU (first part before space)
          const name = img.replace(/\.png$/, ''); // Full product name
          const quantity = formData.quantities[imagePath] || '0';
          return {
            sku,
            name,
            qty: quantity
          };
        })
      }));

      const total_units = emailCategories.reduce((sum: number, cat: any) => 
        sum + cat.items.reduce((catSum: number, item: any) => 
          catSum + Number(item.qty), 0
        ), 0
      );

      const templateParams = {
        store_number: formData.storeNumber,
        manager_name: formData.storeManager,
        date: formData.date,
        categories: emailCategories,
        total_units: total_units.toString(),
        provider_email: PROVIDER_EMAIL,
      };

      console.log('Sending email with params:', templateParams);

      await emailjs.send(
        EMAILJS_SERVICE_ID,
        EMAILJS_TEMPLATE_ID,
        templateParams,
        EMAILJS_USER_ID
      );

      setPage('receipt');
      alert('Order receipt sent to ' + PROVIDER_EMAIL);
    } catch (err) {
      console.error('EmailJS error:', err);
      alert('Failed to send email. Please check your EmailJS configuration and try again.');
    } finally {
      setSending(false);
    }
  };

  if (page === 'summary') {
    return (
      <div style={{ background: 'var(--color-bg)', minHeight: '100vh', padding: 'var(--space-3)' }}>
        <h1 style={{ color: 'var(--color-primary)', marginBottom: 'var(--space-3)' }}>Order Summary</h1>
        <div style={{ background: 'var(--color-bg-alt)', borderRadius: 'var(--radius)', padding: 'var(--space-3)', marginBottom: '2rem' }}>
          <h2 style={{ color: 'var(--color-primary)' }}>Store Information</h2>
          <div style={{ marginBottom: '1rem' }}><strong>Store Number:</strong> {formData.storeNumber}</div>
          <div style={{ marginBottom: '1rem' }}><strong>Store Manager:</strong> {formData.storeManager}</div>
          <div style={{ marginBottom: '1rem' }}><strong>Date:</strong> {formData.date}</div>
        </div>
        {categories.map((cat) => (
          <section key={cat.name} style={{ marginBottom: '2rem', background: 'var(--color-bg-alt)', borderRadius: 'var(--radius)', padding: 'var(--space-3)' }}>
            <h2 style={{ color: 'var(--color-primary)', marginBottom: 'var(--space-2)' }}>{cat.name}</h2>
            <div style={{ display: 'flex', flexWrap: 'wrap', gap: 'var(--space-2)' }}>
              {cat.images.map((img) => {
                const imagePath = `${cat.path}/${img}`;
                const productName = img.replace(/\.png$/, '');
                const qty = formData.quantities[imagePath] || '0';
                return (
                  <div key={img} style={{ width: 200, marginBottom: 'var(--space-2)' }}>
                    <img
                      src={process.env.PUBLIC_URL + `/MichiganState/${imagePath}`}
                      alt={img}
                      style={{ width: '100%', borderRadius: 'var(--radius)', boxShadow: '0 2px 8px rgba(0,0,0,0.06)' }}
                    />
                    <div style={{ fontSize: 12, marginTop: 4, marginBottom: 4 }}>{productName}</div>
                    <div style={{ fontWeight: 'bold', fontSize: 14 }}>Qty: {qty}</div>
                  </div>
                );
              })}
            </div>
          </section>
        ))}
        <div style={{ display: 'flex', gap: '1rem', marginTop: '2rem' }}>
          <button
            type="button"
            onClick={handleBack}
            style={{
              background: 'var(--color-primary)',
              color: 'white',
              padding: '12px 24px',
              border: 'none',
              borderRadius: 'var(--radius)',
              fontSize: '16px',
              cursor: 'pointer',
              flex: 1
            }}
          >
            Back
          </button>
          <button
            type="button"
            onClick={handleConfirm}
            style={{
              background: 'var(--color-primary)',
              color: 'white',
              padding: '12px 24px',
              border: 'none',
              borderRadius: 'var(--radius)',
              fontSize: '16px',
              cursor: 'pointer',
              flex: 1
            }}
            disabled={sending}
          >
            {sending ? 'Sending...' : 'Confirm'}
          </button>
        </div>
      </div>
    );
  }

  if (page === 'receipt') {
    return (
      <div style={{ background: '#fff', minHeight: '100vh', padding: 'var(--space-3)', fontFamily: 'monospace' }}>
        <h1 style={{ color: 'var(--color-primary)', marginBottom: 'var(--space-3)', textAlign: 'center' }}>Order Receipt</h1>
        <div style={{ maxWidth: 500, margin: '0 auto', border: '1px solid #ccc', borderRadius: 'var(--radius)', padding: 'var(--space-3)', background: '#fafafa' }}>
          <div style={{ marginBottom: '1rem' }}><strong>Store Number:</strong> {formData.storeNumber}</div>
          <div style={{ marginBottom: '1rem' }}><strong>Store Manager:</strong> {formData.storeManager}</div>
          <div style={{ marginBottom: '2rem' }}><strong>Date:</strong> {formData.date}</div>
          {categories.map((cat) => (
            <div key={cat.name} style={{ marginBottom: '1.5rem' }}>
              <div style={{ fontWeight: 'bold', borderBottom: '1px solid #ccc', marginBottom: 4 }}>{cat.name}</div>
              {cat.images.map((img) => {
                const imagePath = `${cat.path}/${img}`;
                const productName = img.replace(/\.png$/, '');
                const qty = formData.quantities[imagePath] || '0';
                return (
                  <div key={img} style={{ display: 'flex', justifyContent: 'space-between', padding: '2px 0', fontSize: 15 }}>
                    <span>{productName}</span>
                    <span>Qty: {qty}</span>
                  </div>
                );
              })}
            </div>
          ))}
        </div>
      </div>
    );
  }

  // FORM PAGE
  return (
    <div style={{ background: 'var(--color-bg)', minHeight: '100vh', padding: 'var(--space-3)' }}>
      <h1 style={{ color: 'var(--color-primary)', marginBottom: 'var(--space-3)' }}>Michigan State Product Order Form</h1>
      <form onSubmit={handleFormSubmit}>
        <div style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))',
          gap: 'var(--space-2)',
          marginBottom: 'var(--space-3)',
          background: 'var(--color-bg-alt)',
          padding: 'var(--space-3)',
          borderRadius: 'var(--radius)'
        }}>
          <div>
            <label htmlFor="storeNumber" style={{ display: 'block', marginBottom: '4px', fontWeight: 'bold' }}>
              Store Number:
            </label>
            <input
              type="text"
              id="storeNumber"
              value={formData.storeNumber}
              onChange={(e) => setFormData(prev => ({ ...prev, storeNumber: e.target.value }))}
              style={{
                width: '100%',
                padding: '8px',
                border: '1px solid #ccc',
                borderRadius: 'var(--radius)',
                fontSize: '14px'
              }}
              required
            />
          </div>
          <div>
            <label htmlFor="storeManager" style={{ display: 'block', marginBottom: '4px', fontWeight: 'bold' }}>
              Store Manager:
            </label>
            <input
              type="text"
              id="storeManager"
              value={formData.storeManager}
              onChange={(e) => setFormData(prev => ({ ...prev, storeManager: e.target.value }))}
              style={{
                width: '100%',
                padding: '8px',
                border: '1px solid #ccc',
                borderRadius: 'var(--radius)',
                fontSize: '14px'
              }}
              required
            />
          </div>
          <div>
            <label htmlFor="date" style={{ display: 'block', marginBottom: '4px', fontWeight: 'bold' }}>
              Date:
            </label>
            <input
              type="date"
              id="date"
              value={formData.date}
              onChange={(e) => setFormData(prev => ({ ...prev, date: e.target.value }))}
              style={{
                width: '100%',
                padding: '8px',
                border: '1px solid #ccc',
                borderRadius: 'var(--radius)',
                fontSize: '14px'
              }}
              required
            />
          </div>
        </div>

        {categories.map((cat) => (
          <section key={cat.name} style={{ marginBottom: '2rem', background: 'var(--color-bg-alt)', borderRadius: 'var(--radius)', padding: 'var(--space-3)' }}>
            <h2 style={{ color: 'var(--color-primary)', marginBottom: 'var(--space-2)' }}>{cat.name}</h2>
            <div style={{ display: 'flex', flexWrap: 'wrap', gap: 'var(--space-2)' }}>
              {cat.images.map((img) => {
                const imagePath = `${cat.path}/${img}`;
                const productName = img.replace(/\.png$/, '');
                return (
                  <div key={img} style={{ width: 200, marginBottom: 'var(--space-2)' }}>
                    <img
                      src={process.env.PUBLIC_URL + `/MichiganState/${imagePath}`}
                      alt={img}
                      style={{ width: '100%', borderRadius: 'var(--radius)', boxShadow: '0 2px 8px rgba(0,0,0,0.06)' }}
                    />
                    <div style={{ fontSize: 12, marginTop: 4, marginBottom: 4 }}>{productName}</div>
                    <div style={{ display: 'flex', alignItems: 'center', gap: '8px' }}>
                      <label htmlFor={`qty-${imagePath}`} style={{ fontSize: 12, fontWeight: 'bold' }}>
                        Qty:
                      </label>
                      <input
                        type="number"
                        id={`qty-${imagePath}`}
                        min="0"
                        value={formData.quantities[imagePath] || ''}
                        onChange={(e) => handleQuantityChange(imagePath, e.target.value)}
                        style={{
                          width: '60px',
                          padding: '4px',
                          border: '1px solid #ccc',
                          borderRadius: 'var(--radius)',
                          fontSize: '12px'
                        }}
                        required
                      />
                    </div>
                  </div>
                );
              })}
            </div>
          </section>
        ))}

        {error && <div style={{ color: 'red', marginBottom: '1rem', fontWeight: 'bold' }}>{error}</div>}
        <button
          type="submit"
          style={{
            background: 'var(--color-primary)',
            color: 'white',
            padding: '12px 24px',
            border: 'none',
            borderRadius: 'var(--radius)',
            fontSize: '16px',
            cursor: 'pointer',
            marginBottom: 'var(--space-3)',
            marginTop: '2rem',
            display: 'block',
            width: '100%'
          }}
        >
          Review
        </button>
      </form>
    </div>
  );
}

export default App;
